const body = $json.body || {};
// Expected GHL fields
const data = {
  clientGhlKey: body.clientGhlKey || body.ghlKey || '',
  contactId: body.contactId || body.contact_id || '',
  contactName: body.contact_name || body.firstName || 'Cliente',
  contactEmail: body.contact_email || body.email || '',
  contactPhone: body.contact_phone || body.phone || '',
  businessName: body.business_name || body.location_name || 'Nosso negocio',
  reviewLink: body.review_link || body.google_review_link || ''
};

// Build message in Portuguese
const message = 'Oi, ' + data.contactName.split(' ')[0] + '! Obrigado por confiar na ' + data.businessName + '. Sua opiniao faz muita diferenca pra gente. Pode dar 1 minutinho e deixar uma avaliacao no Google? ' + (data.reviewLink || 'Responde esse SMS com uma nota de 1 a 5 que eu te mando o link.');

return [{ json: { ...data, message } }];
